  1→"use client";
  2→
  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import dynamic from "next/dynamic";
  5→import ReactMarkdown from "react-markdown";
  6→import remarkGfm from "remark-gfm";
  7→import { chatStream } from "@/lib/api";
  8→import type { CanvasState } from "@/components/OmegaCanvas";
  9→import s from "./page.module.css";
 10→
 11→const OmegaCanvas = dynamic(() => import("@/components/OmegaCanvas"), { ssr: false });
 12→
 13→// Removed useTypewriter Hook — upgraded to real streaming
 14→
 15→// ── Types ─────────────────────────────────────────────────────────
 16→interface Msg { role: "user" | "omega"; text: string; timestamp?: string; }
 17→
 18→// ── CodeBlock ─────────────────────────────────────────────────────
 19→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 20→function CodeBlock({ inline, className, children, ...props }: any) {
 21→  const match = /language-(\w+)/.exec(className || "");
 22→  const [copied, setCopied] = useState(false);
 23→  
 24→  const hCopy = () => {
 25→    navigator.clipboard.writeText(String(children).replace(/\n$/, ""));
 26→    setCopied(true);
 27→    setTimeout(() => setCopied(false), 2000);
 28→  };
 29→
 30→  if (!inline && match) {
 31→    return (
 32→      <div className={`${s.codeBlockWrap} ${s.staggerBlock}`}>
 33→        <div className={s.codeHeader}>
 34→          <span className={s.codeLang}>{match[1]}</span>
 35→          <button className={s.codeCopyBtn} onClick={hCopy} aria-label="Copy code">
 36→            {copied ? "✓ Copied" : "Copy"}
 37→          </button>
 38→        </div>
 39→        <pre className={s.codePre}><code className={className} {...props}>{children}</code></pre>
 40→      </div>
 41→    );
 42→  }
 43→  return <code className={className} {...props}>{children}</code>;
 44→}
 45→
 46→// ── Markdown Components ───────────────────────────────────────────
 47→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 48→const mdComponents: any = {
 49→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 50→  p: ({ children }: any) => <p className={s.staggerBlock}>{children}</p>,
 51→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 52→  h1: ({ children }: any) => <h1 className={s.staggerBlock}>{children}</h1>,
 53→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 54→  h2: ({ children }: any) => <h2 className={s.staggerBlock}>{children}</h2>,
 55→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 56→  h3: ({ children }: any) => <h3 className={s.staggerBlock}>{children}</h3>,
 57→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 58→  ul: ({ children }: any) => <ul className={s.staggerBlock}>{children}</ul>,
 59→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 60→  ol: ({ children }: any) => <ol className={s.staggerBlock}>{children}</ol>,
 61→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 62→  blockquote: ({ children }: any) => <blockquote className={s.staggerBlock}>{children}</blockquote>,
 63→  code: CodeBlock,
 64→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 65→  table: ({ children }: any) => (
 66→    <div className={`${s.tableWrap} ${s.staggerBlock}`}>
 67→      <table>{children}</table>
 68→    </div>
 69→  )
 70→};
 71→
 72→// ── OmegA message with streaming ─────────────────────────────────
 73→function OmegaMsg({ text, animate, timestamp }: { text: string; animate: boolean; timestamp?: string }) {
 74→  const streaming = animate;
 75→  const [copied, setCopied] = useState(false);
 76→
 77→  const copy = () => {
 78→    navigator.clipboard.writeText(text).then(() => {
 79→      setCopied(true);
 80→      setTimeout(() => setCopied(false), 2000);
 81→    });
 82→  };
 83→
 84→  return (
 85→    <div className={s.msgOmega}>
 86→      <span className={s.omegaGlyph}>Ω</span>
 87→      <div className={s.omegaBody}>
 88→        <div className={`${s.omegaText} ${streaming ? s.streaming : ""}`}>
 89→          <ReactMarkdown remarkPlugins={[remarkGfm]} components={mdComponents}>{text}</ReactMarkdown>
 90→          {streaming && <span className={s.cursor} />}
 91→        </div>
 92→        {!streaming && (
 93→          <div className={s.omegaFooter}>
 94→            {timestamp && <span className={s.msgTimestamp}>{new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>}
 95→            <button
 96→              className={s.copyBtn}
 97→              onClick={copy}
 98→              title="Copy"
 99→              aria-label={copied ? "Copied to clipboard" : "Copy response"}
100→            >
101→              {copied ? "✓ Copied" : "Copy"}
102→            </button>
103→          </div>
104→        )}
105→      </div>
106→    </div>
107→  );
108→}
109→
110→// ── Thinking Indicator ───────────────────────────────────────────
111→const THINKING_STATES = ["reading memory...", "synthesizing...", "forming response..."];
112→
113→function ThinkingIndicator({ status }: { status?: string | null }) {
114→  const [idx, setIdx] = useState(0);
115→  useEffect(() => {
116→    const id = setInterval(() => setIdx(i => (i + 1) % THINKING_STATES.length), 2000);
117→    return () => clearInterval(id);
118→  }, []);
119→
120→  return (
121→    <div className={s.thinkingIndicator}>
122→      <span className={s.omegaGlyph}>Ω</span>
123→      <div className={s.thinkingContent}>
124→        {status ? (
125→          <div className={s.thinkingStatusText}>{status}</div>
126→        ) : (
127→          <>
128→            <div className={s.thinkingDots}>
129→              <span /><span /><span />
130→            </div>
131→            <div className={s.thinkingLabelWrap}>
132→              {THINKING_STATES.map((txt, i) => (
133→                <span key={txt} className={`${s.thinkingLabelItem} ${i === idx ? s.active : ""}`}>
134→                  {txt}
135→                </span>
136→              ))}
137→            </div>
138→          </>
139→        )}
140→      </div>
141→    </div>
142→  );
143→}
144→
145→function formatRelativeTime(dateStr: string) {
146→  if (!dateStr) return "";
147→  const diff = Math.max(0, Date.now() - new Date(dateStr).getTime());
148→  const minutes = Math.floor(diff / 60000);
149→  if (minutes < 1) return `just now`;
150→  if (minutes < 60) return `${minutes}m ago`;
151→  const hours = Math.floor(minutes / 60);
152→  if (hours < 24) return `${hours}h ago`;
153→  const days = Math.floor(hours / 24);
154→  if (days === 1) return `yesterday`;
155→  return `${days}d ago`;
156→}
