 91→async function pullRawContext(userMessage: string): Promise<string> {
 92→  const dbUrl = process.env.DATABASE_URL;
 93→  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';
 94→
 95→  const db = neon(dbUrl);
 96→  const sections: string[] = [];
 97→
 98→  // ── BEDROCK: identity anchor loads first, before everything else ──
 99→  const anchor = await pullIdentityAnchor(db);
100→  if (anchor) sections.push(anchor);
101→
102→  // ── PROVENANCE SEAL: Yettragrammaton — always present, hardcoded ──
103→  sections.push(YETTRAGRAMMATON);
104→
105→  // Recent memory entries — the raw record, not the sanitized version
106→  const recent = await db`
107→    SELECT LEFT(content, 2500) AS content, created_at
108→    FROM omega_memory_entries
109→    ORDER BY created_at DESC
110→    LIMIT 20
111→  `.catch(() => [] as Row[]);
112→
113→  if ((recent as Row[]).length > 0) {
114→    sections.push('=== RECENT MEMORY ENTRIES ===');
115→    for (const r of recent as Row[]) {
116→      sections.push(`[${r.created_at}]\n${r.content}`);
117→    }
118→  }
119→
120→  // Query-relevant entries — what matches what the person is actually asking about
121→  const keywords = userMessage
122→    .toLowerCase()
123→    .replace(/[^a-z0-9 ]/g, ' ')
124→    .split(/\s+/)
125→    .filter(w => w.length > 3)
126→    .slice(0, 3);
127→
128→  if (keywords.length > 0) {
129→    const pattern = `%${keywords[0]}%`;
130→    const relevant = await db`
131→      SELECT LEFT(content, 2000) AS content, created_at
132→      FROM omega_memory_entries
133→      WHERE content ILIKE ${pattern}
134→      ORDER BY created_at DESC
135→      LIMIT 10
136→    `.catch(() => [] as Row[]);
137→
138→    if ((relevant as Row[]).length > 0) {
139→      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
140→      for (const r of relevant as Row[]) {
141→        sections.push(`[${r.created_at}]\n${r.content}`);
142→      }
143→    }
144→  }
145→
146→  // Marginalia — raw notes and observations logged over time
147→  const marginalia = await db`
148→    SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15
149→  `.catch(() => [] as Row[]);
150→
151→  if ((marginalia as Row[]).length > 0) {
152→    sections.push('\n=== MARGINALIA ===');
153→    for (const m of marginalia as Row[]) {
154→      sections.push(JSON.stringify(m));
155→    }
156→  }
157→
158→  // System events — what actually happened and when
159→  const events = await db`
160→    SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15
161→  `.catch(() => [] as Row[]);
162→
163→  if ((events as Row[]).length > 0) {
164→    sections.push('\n=== SYSTEM EVENTS ===');
165→    for (const e of events as Row[]) {
166→      sections.push(JSON.stringify(e));
167→    }
168→  }
169→
170→  // System improvements — things noticed and changed over time
171→  const improvements = await db`
172→    SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10
173→  `.catch(() => [] as Row[]);
174→
175→  if ((improvements as Row[]).length > 0) {
176→    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
177→    for (const i of improvements as Row[]) {
178→      sections.push(JSON.stringify(i));
179→    }
180→  }
181→
182→  return sections.join('\n\n');
183→}
