201→/** Fetch the gateway with timeout, AbortController, and 1x retry on timeout */
202→async function fetchGateway(body: string): Promise<Response> {
203→  let lastError: Error | null = null;
204→
205→  for (let attempt = 0; attempt <= GATEWAY_RETRIES; attempt++) {
206→    const controller = new AbortController();
207→    const timer = setTimeout(() => controller.abort(), GATEWAY_TIMEOUT_MS);
208→
209→    try {
210→      const res = await fetch(`${GATEWAY}/api/v1/chat`, {
211→        method: 'POST',
212→        headers: {
213→          'Content-Type': 'application/json',
214→          Authorization: `Bearer ${BEARER}`,
215→        },
216→        body,
217→        signal: controller.signal,
218→      });
219→      clearTimeout(timer);
220→      return res;
221→    } catch (err) {
222→      clearTimeout(timer);
223→      lastError = err instanceof Error ? err : new Error(String(err));
224→
225→      const isTimeout = lastError.name === 'AbortError';
226→      // Only retry on timeout, not on other fetch errors
227→      if (!isTimeout || attempt >= GATEWAY_RETRIES) break;
228→      // else loop for retry
229→    }
230→  }
231→
232→  throw lastError;
233→}
