235→export async function POST(req: NextRequest) {
236→  try {
237→    const { user, history, sessionId } = (await req.json()) as { user: string; history?: Msg[]; sessionId?: string };
238→
239→    if (!user?.trim()) {
240→      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
241→    }
242→
243→    const dbUrl = process.env.DATABASE_URL;
244→    let finalSessionId = sessionId;
245→
246→    // Fast session creation if needed to set the header immediately
247→    if (dbUrl && !finalSessionId) {
248→      try {
249→        const db = neon(dbUrl);
250→        const sessionRes = await db`INSERT INTO omega_sessions DEFAULT VALUES RETURNING id`;
251→        if (sessionRes && sessionRes.length > 0) {
252→          finalSessionId = sessionRes[0].id as string;
253→        }
254→      } catch (err) {
255→        console.error('[OmegA chat] Session creation failed', err);
256→      }
257→    }
258→
259→    const encoder = new TextEncoder();
260→    const decoder = new TextDecoder();
261→    
262→    let provider = "omega-gateway";
263→    const customStream = new ReadableStream({
264→      async start(controller) {
265→        try {
266→          // Status: reading memory...
267→          controller.enqueue(encoder.encode('data: {"type":"status","text":"reading memory..."}\n\n'));
268→
269→          // 1. Thread context and persistence
270→          if (dbUrl && finalSessionId) {
271→             // Non-blocking log for user message
272→             const db = neon(dbUrl);
273→             db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`
274→               .catch(e => console.error('[OmegA chat db msg error]', e));
275→          }
276→
277→          // 2. Fetch all raw context entries
278→          let rawContext: string;
279→          try {
280→            rawContext = await pullRawContext(user);
281→          } catch (dbErr) {
282→            console.warn('[OmegA chat] DB pull failed:', dbErr);
283→            rawContext = '(Memory bank unreachable — reasoning independently)';
284→          }
285→
286→          // Status: synthesizing...
287→          controller.enqueue(encoder.encode('data: {"type":"status","text":"synthesizing..."}\n\n'));
288→
289→          // 3. Assemble full OmegA prompt block
290→          const conversationContext = history?.length 
291→            ? `\n━━━ SESSION CONVERSATION HISTORY ━━━\n\n` + 
292→              history.map(m => `[${m.role === 'omega' ? 'OmegA' : 'User'}]: ${m.text}`).join('\n\n') +
293→              `\n\n━━━ END HISTORY ━━━\n`
294→            : '';
295→          
296→          const computeContext = `\n\n[COMPUTE CONTEXT: You are running on ${process.env.ANTHROPIC_API_KEY ? "Claude 3.5 Sonnet (Fallback)" : "OmegA Gateway"}.]`
297→          const system = `${SYNTHESIS_DIRECTIVE}${computeContext}\n\n━━━ RAW DATA FROM MEMORY SYSTEMS ━━━\n\n${rawContext}\n\n━━━ END RAW DATA ━━━\n${conversationContext}`;
298→
299→          // 4. Proxy to gateway (main) or anthropic (fallback)
300→          let responseStream: ReadableStream;
301→          // (provider moved out)
302→
303→          try {
304→            const upstream = await fetchGateway(JSON.stringify({
305→              user,
306→              history: history?.map(h => ({ role: h.role === "omega" ? "assistant" : "user", content: h.text })) || [],
307→              namespace: 'synthesis',
308→              use_memory: false,
309→              temperature: 0.85,
310→              mode: 'omega',
311→              system,
312→              stream: true
313→            }));
314→            
315→            if (!upstream.ok) throw new Error(`Gateway: ${upstream.status}`);
316→            if (!upstream.body) throw new Error("Gateway empty body");
317→            responseStream = upstream.body;
318→            
319→          } catch (err) {
320→            const Key = process.env._API_KEY ?? process.env.NEXT_PUBLIC__API_KEY;
321→            if (Key) {
322→              console.warn('[OmegA chat]  fallback active:', err);
323→              provider = "-fallback";
324→              const genai = new GoogleGenAI({ apiKey: Key });
325→              const History = (history || []).map(h => ({
326→                role: h.role === "omega" ? "model" : "user",
327→                parts: [{ text: h.text }],
328→              }));
329→              const chat = genai.chats.create({
330→                model: "-2.5-flash",
331→                config: { systemInstruction: system, temperature: 0.85, maxOutputTokens: 4096 },
332→                history: History,
333→              });
334→              const Stream = await chat.sendMessageStream({ message: user });
335→              responseStream = new ReadableStream({
336→                async start(ctrl) {
337→                  for await (const chunk of Stream) {
338→                    const text = chunk.text ?? '';
339→                    if (text) ctrl.enqueue(encoder.encode(text));
340→                  }
341→                  ctrl.close();
342→                }
343→              });
344→            } else if (process.env.ANTHROPIC_API_KEY) {
345→              console.warn('[OmegA chat] Anthropic fallback active:', err);
346→              provider = "anthropic-fallback";
347→              const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
348→              const hist: Anthropic.MessageParam[] = history?.map(h => ({ role: h.role === "omega" ? "assistant" : "user", content: h.text })) || [];
349→              hist.push({ role: "user", content: user });
350→              const anthRes = await anthropic.messages.create({
351→                model: "claude-3-5-sonnet-latest",
352→                max_tokens: 4096,
353→                system,
354→                messages: hist,
355→                stream: true
356→              });
357→              responseStream = new ReadableStream({
358→                async start(ctrl) {
359→                  for await (const chunk of anthRes) {
360→                    if (chunk.type === "content_block_delta" && chunk.delta.type === "text_delta") {
361→                      ctrl.enqueue(encoder.encode(chunk.delta.text));
362→                    }
363→                  }
364→                  ctrl.close();
365→                }
366→              });
367→            } else {
368→              throw err;
369→            }
370→          }
371→
372→          // 5. Pipe tokens through and capture for persistent history
373→          let fullResponse = "";
374→          const reader = responseStream.getReader();
375→          while (true) {
376→            const { value, done } = await reader.read();
377→            if (done) break;
378→            fullResponse += decoder.decode(value, { stream: true });
379→            controller.enqueue(value);
380→          }
381→          fullResponse += decoder.decode();
382→
383→          // Save history asynchronously
384→          if (dbUrl && finalSessionId && fullResponse) {
385→            const db = neon(dbUrl);
386→            db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`
387→              .catch(e => console.error('[OmegA chat db end error]', e));
388→          }
389→
390→          controller.close();
391→        } catch (err) {
392→          console.error('[OmegA chat stream error]', err);
393→          controller.error(err);
394→        }
395→      }
396→    });
397→
398→    return new NextResponse(customStream, {
399→      headers: {
400→        'Content-Type': 'text/plain; charset=utf-8',
401→        'X-Session-Id': finalSessionId || '',
402→        'X-Provider': provider
403→      }
404→    });
405→
406→  } catch (err) {
407→    console.error('[OmegA chat POST error]', err);
408→    return NextResponse.json({ error: String(err) }, { status: 500 });
409→  }
410→}
