  1→"use client";
  2→
  3→import { useEffect, useRef } from "react";
  4→
  5→export type CanvasState = "idle" | "thinking" | "responding";
  6→
  7→interface Particle {
  8→  x: number; y: number;
  9→  vx: number; vy: number;
 10→  size: number;
 11→  opacity: number;
 12→  rgb: string;
 13→  phase: number;
 14→  phaseSpeed: number;
 15→}
 16→
 17→interface FieldLine {
 18→  pts: number[];   // x0,y0, cx1,cy1, cx2,cy2, x1,y1
 19→  vel: number[];   // dx for each control point
 20→  opacity: number;
 21→}
 22→
 23→function hex(h: string): string {
 24→  const r = parseInt(h.slice(1, 3), 16);
 25→  const g = parseInt(h.slice(3, 5), 16);
 26→  const b = parseInt(h.slice(5, 7), 16);
 27→  return `${r},${g},${b}`;
 28→}
 29→
 30→const COLORS = ["#3b4fd8", "#6d4ff5", "#9b7cfa", "#c4b5fd", "#818cf8"].map(hex);
 31→
 32→export default function OmegaCanvas({ state }: { state: CanvasState }) {
 33→  const ref = useRef<HTMLCanvasElement>(null);
 34→  const stateRef = useRef(state);
 35→  useEffect(() => { stateRef.current = state; }, [state]);
 36→
 37→  useEffect(() => {
 38→    const canvas = ref.current;
 39→    if (!canvas) return;
 40→    const ctx = canvas.getContext("2d");
 41→    if (!ctx) return;
 42→
 43→    let raf: number;
 44→    let W = 0, H = 0;
 45→    let frame = 0;
 46→
 47→    const resize = () => {
 48→      W = canvas.width = window.innerWidth;
 49→      H = canvas.height = window.innerHeight;
 50→    };
 51→    window.addEventListener("resize", resize);
 52→    resize();
 53→
 54→    // Particles
 55→    const COUNT = 140;
 56→    const particles: Particle[] = Array.from({ length: COUNT }, () => ({
 57→      x: Math.random() * W,
 58→      y: Math.random() * H,
 59→      vx: (Math.random() - 0.5) * 0.35,
 60→      vy: (Math.random() - 0.5) * 0.35,
 61→      size: Math.random() * 1.8 + 0.4,
 62→      opacity: Math.random() * 0.55 + 0.1,
 63→      rgb: COLORS[Math.floor(Math.random() * COLORS.length)],
 64→      phase: Math.random() * Math.PI * 2,
 65→      phaseSpeed: 0.008 + Math.random() * 0.018,
 66→    }));
 67→
 68→    // Field lines
 69→    const LINES = 10;
 70→    const lines: FieldLine[] = Array.from({ length: LINES }, () => ({
 71→      pts: [
 72→        Math.random() * W, Math.random() * H,
 73→        Math.random() * W, Math.random() * H,
 74→        Math.random() * W, Math.random() * H,
 75→        Math.random() * W, Math.random() * H,
 76→      ],
 77→      vel: Array.from({ length: 8 }, () => (Math.random() - 0.5) * 0.25),
 78→      opacity: Math.random() * 0.07 + 0.02,
 79→    }));
 80→
 81→    const draw = () => {
 82→      raf = requestAnimationFrame(draw);
 83→      frame++;
 84→
 85→      const s = stateRef.current;
 86→      const speed = s === "thinking" ? 2.8 : s === "responding" ? 1.6 : 1;
 87→      const glow = s === "thinking" ? 0.18 + 0.12 * Math.sin(frame * 0.08) : s === "responding" ? 0.08 : 0;
 88→
 89→      // Trailing clear
 90→      ctx.fillStyle = "rgba(2, 2, 12, 0.18)";
 91→      ctx.fillRect(0, 0, W, H);
 92→
 93→      // Central pulse glow when thinking
 94→      if (glow > 0) {
 95→        const g = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, Math.min(W, H) * 0.55);
 96→        g.addColorStop(0, `rgba(99,60,220,${glow})`);
 97→        g.addColorStop(0.5, `rgba(60,40,180,${glow * 0.4})`);
 98→        g.addColorStop(1, "rgba(0,0,0,0)");
 99→        ctx.fillStyle = g;
100→        ctx.fillRect(0, 0, W, H);
101→      }
102→
103→      // Field lines
104→      for (const fl of lines) {
105→        for (let i = 0; i < fl.pts.length; i++) {
106→          fl.pts[i] += fl.vel[i] * speed;
107→          if (fl.pts[i] < -200 || fl.pts[i] > (i % 2 === 0 ? W : H) + 200) fl.vel[i] *= -1;
108→        }
109→        const [x0, y0, cx1, cy1, cx2, cy2, x1, y1] = fl.pts;
110→        const grad = ctx.createLinearGradient(x0, y0, x1, y1);
111→        const op = fl.opacity * (s === "thinking" ? 2.2 : s === "responding" ? 1.4 : 1);
112→        grad.addColorStop(0, `rgba(80,50,220,0)`);
113→        grad.addColorStop(0.5, `rgba(110,70,240,${op})`);
114→        grad.addColorStop(1, `rgba(80,50,220,0)`);
115→        ctx.beginPath();
116→        ctx.moveTo(x0, y0);
117→        ctx.bezierCurveTo(cx1, cy1, cx2, cy2, x1, y1);
118→        ctx.strokeStyle = grad;
119→        ctx.lineWidth = 1;
120→        ctx.stroke();
121→      }
122→
123→      // Connections
124→      const maxDist = s === "thinking" ? 110 : 85;
125→      for (let i = 0; i < particles.length; i++) {
126→        for (let j = i + 1; j < particles.length; j++) {
127→          const dx = particles[i].x - particles[j].x;
128→          const dy = particles[i].y - particles[j].y;
129→          const d = Math.sqrt(dx * dx + dy * dy);
130→          if (d < maxDist) {
131→            const a = (1 - d / maxDist) * 0.12 * (s === "thinking" ? 2.5 : 1);
132→            ctx.beginPath();
133→            ctx.moveTo(particles[i].x, particles[i].y);
134→            ctx.lineTo(particles[j].x, particles[j].y);
135→            ctx.strokeStyle = `rgba(120,80,255,${a})`;
136→            ctx.lineWidth = 0.5;
137→            ctx.stroke();
138→          }
139→        }
140→      }
141→
142→      // Particles
143→      for (const p of particles) {
144→        p.x += p.vx * speed;
145→        p.y += p.vy * speed;
146→        p.phase += p.phaseSpeed * speed;
147→        if (p.x < 0) p.x = W;
148→        if (p.x > W) p.x = 0;
149→        if (p.y < 0) p.y = H;
150→        if (p.y > H) p.y = 0;
151→
152→        const pulse = 0.5 + 0.5 * Math.sin(p.phase);
153→        const op = p.opacity * pulse * (s === "thinking" ? 1.5 : 1);
154→        const sz = p.size * (0.7 + 0.3 * pulse);
155→
156→        // Soft glow
157→        const grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, sz * 5);
158→        grd.addColorStop(0, `rgba(${p.rgb},${op})`);
159→        grd.addColorStop(1, `rgba(${p.rgb},0)`);
160→        ctx.beginPath();
161→        ctx.arc(p.x, p.y, sz * 5, 0, Math.PI * 2);
162→        ctx.fillStyle = grd;
163→        ctx.fill();
164→
165→        // Core
166→        ctx.beginPath();
167→        ctx.arc(p.x, p.y, sz, 0, Math.PI * 2);
168→        ctx.fillStyle = `rgba(${p.rgb},${Math.min(op * 2, 1)})`;
169→        ctx.fill();
170→      }
171→
172→      // Arc sparks when thinking
173→      if (s === "thinking" && frame % 8 === 0) {
174→        const cx = W / 2 + (Math.random() - 0.5) * 60;
175→        const cy = H / 2 + (Math.random() - 0.5) * 60;
176→        ctx.beginPath();
177→        ctx.arc(cx, cy, Math.random() * 80 + 20, 0, Math.PI * 2 * Math.random());
178→        ctx.strokeStyle = `rgba(180,140,255,${Math.random() * 0.15})`;
179→        ctx.lineWidth = 0.5;
180→        ctx.stroke();
181→      }
182→    };
183→
184→    draw();
185→    return () => {
186→      cancelAnimationFrame(raf);
187→      window.removeEventListener("resize", resize);
188→    };
189→  }, []);
190→
191→  return (
192→    <canvas
193→      ref={ref}
194→      style={{
195→        position: "fixed", inset: 0,
196→        width: "100%", height: "100%",
197→        zIndex: 0, pointerEvents: "none",
198→        background: "#02020c",
199→        willChange: "transform",
200→      }}
201→    />
202→  );
203→}
